from jinja2 import Environment
from jinja2.ext import i18n
from jinja2 import nodes
from jinja2.exceptions import TemplateAssertionError

env = Environment(extensions=[i18n])
env.install_null_translations()

def get_output(src):
    ast = env.parse(src)
    return [n for n in ast.body if isinstance(n, nodes.Output)][0]

results = []
def t(name, fn):
    try:
        fn()
        results.append((name, "OK"))
    except Exception as e:
        results.append((name, f"FAIL: {e!r}"))

t("1-basic-note", lambda: (
    (lambda o: (
        (_ for _ in ()).throw(AssertionError(o.trans_metadata)) if o.trans_metadata != {"note": "Context for translators"} else None
    ))(get_output('{% trans note="Context for translators" %}Hello World{% endtrans %}'))
))

def check2():
    src2 = '{% trans note="User count", created="2024-01-01" %}{{ count }} user{% pluralize %}{{ count }} users{% endtrans %}'
    out2 = get_output(src2)
    assert out2.trans_metadata == {"note": "User count", "created": "2024-01-01"}, out2.trans_metadata
    assert env.from_string(src2).render(count=1) == "1 user"
    assert env.from_string(src2).render(count=5) == "5 users"
t("2-multi-plural", check2)

def check3():
    src3 = '{% trans user_count, note="Message with variable" %}{{ user_count }} item{% endtrans %}'
    out3 = get_output(src3)
    assert out3.trans_metadata == {"note": "Message with variable"}
    assert env.from_string(src3).render(user_count=3) == "3 item"
t("3-var-order", check3)

def check4():
    src4 = '{% trans note="Trimmed message", trimmed %}  Hello  World  {% endtrans %}'
    out4 = get_output(src4)
    assert out4.trans_metadata == {"note": "Trimmed message"}
    assert env.from_string(src4).render() == "Hello World"
t("4-trimmed", check4)

def check5():
    out5 = get_output('{% trans %}Hello World{% endtrans %}')
    assert not hasattr(out5, "trans_metadata")
t("5-no-metadata", check5)

def check6():
    src6 = '{% trans note="test", user_count, trimmed %}  {{ user_count }} items  {% endtrans %}'
    out6 = get_output(src6)
    assert out6.trans_metadata == {"note": "test"}
    assert env.from_string(src6).render(user_count=2) == "2 items"
t("6-required-example", check6)

def check7():
    try:
        env.parse('{% trans note=some_var %}Hello{% endtrans %}')
        raise AssertionError("no raise")
    except TemplateAssertionError as e:
        assert "note" in str(e) and "string literal" in str(e), str(e)
t("7-nonstring-var", check7)

def check7b():
    try:
        env.parse('{% trans note=1+2 %}Hello{% endtrans %}')
        raise AssertionError("no raise")
    except TemplateAssertionError as e:
        assert "note" in str(e) and "string literal" in str(e), str(e)
t("7b-nonstring-expr", check7b)

def check8():
    try:
        env.parse('{% trans note %}Hello{% endtrans %}')
        raise AssertionError("no raise")
    except TemplateAssertionError as e:
        assert "note" in str(e) and "requires a value assignment" in str(e), str(e)
t("8-missing-assign", check8)

def check8b():
    for name in ("created", "modified"):
        try:
            env.parse('{% trans ' + name + ' %}Hello{% endtrans %}')
            raise AssertionError("no raise for " + name)
        except TemplateAssertionError as e:
            assert name in str(e) and "requires a value assignment" in str(e), str(e)
t("8b-missing-assign-others", check8b)

def check9():
    out9 = get_output('{% trans note="" %}Hello{% endtrans %}')
    assert out9.trans_metadata == {"note": ""}
t("9-empty-string", check9)

def check10():
    out10 = get_output('{% trans note="日本語 & <special> \'chars\'" %}Hello{% endtrans %}')
    assert out10.trans_metadata["note"] == "日本語 & <special> 'chars'"
t("10-unicode", check10)

def check11():
    long_str = "x" * 5000
    out11 = get_output('{% trans note="' + long_str + '" %}Hello{% endtrans %}')
    assert out11.trans_metadata["note"] == long_str
t("11-long-string", check11)

def check12():
    src12 = '{% trans note="n", created="c", modified="m" %}Hello{% endtrans %}'
    out12 = get_output(src12)
    assert out12.trans_metadata == {"note": "n", "created": "c", "modified": "m"}
t("12-all-three", check12)

def check13():
    from jinja2.ext import babel_extract
    import io
    src2 = '{% trans note="User count", created="2024-01-01" %}{{ count }} user{% pluralize %}{{ count }} users{% endtrans %}'
    msgs = list(babel_extract(io.BytesIO(src2.encode()), ["gettext", "ngettext", "_"], [], {}))
    assert len(msgs) == 1 and msgs[0][1] == "ngettext", msgs
t("13-babel-extract", check13)

def check14():
    a = env.from_string('{% trans %}Hello World{% endtrans %}').render()
    b = env.from_string('{% trans note="x" %}Hello World{% endtrans %}').render()
    assert a == b == "Hello World"
t("14-render-identical", check14)

def check15():
    src15 = '{% trans author="ignored-not-metadata" %}Hello{% endtrans %}'
    out15 = get_output(src15)
    assert not hasattr(out15, "trans_metadata")
    assert env.from_string(src15).render() == "Hello"
t("15-invalid-name-as-var", check15)

for name, status in results:
